import{c as t,Q as a,j as n,m as s}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"Continual Harness: Online Adaptation for Self-Improving Foundation Agents","description":"","frontmatter":{"title":"Continual Harness: Online Adaptation for Self-Improving Foundation Agents","authors":"Seth Karten, Joel Zhang, Tersoo Upaa Jr, Ruirong Feng, Wenzhe Li, Chengshuai Shi, Chi Jin, Kiran Vodrahalli","published":"2026-05-11T00:00:00.000Z","source":"https://arxiv.org/abs/2605.09998"},"headers":[],"relativePath":"research/papers/2026-05-11-continual-harness-online-adaptation-2605-09998.md","filePath":"research/papers/2026-05-11-continual-harness-online-adaptation-2605-09998.md","lastUpdated":1779901665000}'),o={name:"research/papers/2026-05-11-continual-harness-online-adaptation-2605-09998.md"};function i(r,e,l,p,d,h){return a(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="continual-harness-online-adaptation-for-self-improving-foundation-agents" tabindex="-1">Continual Harness: Online Adaptation for Self-Improving Foundation Agents <a class="header-anchor" href="#continual-harness-online-adaptation-for-self-improving-foundation-agents" aria-label="Permalink to &quot;Continual Harness: Online Adaptation for Self-Improving Foundation Agents&quot;">​</a></h1><p><strong>Authors</strong>: Seth Karten, Joel Zhang, Tersoo Upaa Jr, Ruirong Feng, Wenzhe Li, Chengshuai Shi, Chi Jin, Kiran Vodrahalli <strong>Published</strong>: May 11, 2026 <strong>Source</strong>: <a href="https://arxiv.org/abs/2605.09998" target="_blank" rel="noreferrer">https://arxiv.org/abs/2605.09998</a><strong>arXiv ID</strong>: 2605.09998 <strong>Categories</strong>: cs.LG, cs.AI</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>A framework enabling embodied agents to autonomously refine their operational scaffolding during extended interactions—<strong>without environment resets</strong>. Foundation models wrapped with adaptive components (system prompts, sub-agents, skills, persistent memory) iteratively improve performance in a single continuous episode. Demonstrated as the first AI system to complete multiple Pokémon RPGs.</p><hr><h2 id="three-progressive-contributions" tabindex="-1">Three Progressive Contributions <a class="header-anchor" href="#three-progressive-contributions" aria-label="Permalink to &quot;Three Progressive Contributions&quot;">​</a></h2><h3 id="_1-gemini-plays-pokemon-gpp-human-in-the-loop-phase" tabindex="-1">1. Gemini Plays Pokémon (GPP): Human-in-the-Loop Phase <a class="header-anchor" href="#_1-gemini-plays-pokemon-gpp-human-in-the-loop-phase" aria-label="Permalink to &quot;1. Gemini Plays Pokémon (GPP): Human-in-the-Loop Phase&quot;">​</a></h3><p>Human-supervised harness refinement across three complete Pokémon games:</p><ul><li>Pokémon Blue (May 2025)</li><li>Pokémon Yellow Legacy hard mode, no failed battles (August 2025)</li><li>Pokémon Crystal (November 2025)</li></ul><p>Emergent self-improvement behaviors without explicit prompting:</p><ul><li>Model spontaneously wrapped tool inefficiencies into reusable primitives</li><li>Developed named multi-stage strategies</li><li>Authored explicit problem representations</li></ul><h3 id="_2-continual-harness-automated-mid-episode-refinement" tabindex="-1">2. Continual Harness: Automated Mid-Episode Refinement <a class="header-anchor" href="#_2-continual-harness-automated-mid-episode-refinement" aria-label="Permalink to &quot;2. Continual Harness: Automated Mid-Episode Refinement&quot;">​</a></h3><p>Replaces human intervention with automated Refiner component. Every F steps (after warm-up), the Refiner analyzes recent trajectory windows for failure signatures and emits structured edits.</p><h3 id="_3-model-harness-co-learning" tabindex="-1">3. Model-Harness Co-Learning <a class="header-anchor" href="#_3-model-harness-co-learning" aria-label="Permalink to &quot;3. Model-Harness Co-Learning&quot;">​</a></h3><p>Joint optimization of model weights and harness components during reset-free training using open-source Gemma-4 (31B dense) + DAgger + process-reward-model scoring.</p><hr><h2 id="architecture-two-loop-system" tabindex="-1">Architecture: Two-Loop System <a class="header-anchor" href="#architecture-two-loop-system" aria-label="Permalink to &quot;Architecture: Two-Loop System&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Inner Loop (Agent Action):</span></span>
<span class="line"><span>  Model wrapped in current harness → processes observations → selects actions</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Outer Loop (Harness Refinement):</span></span>
<span class="line"><span>  Every F steps after warm-up:</span></span>
<span class="line"><span>    Refiner analyzes trajectory window for failure signatures</span></span>
<span class="line"><span>    Emits CRUD operations on 4 harness components</span></span></code></pre></div><h3 id="four-harness-components-crud-editable" tabindex="-1">Four Harness Components (CRUD-editable) <a class="header-anchor" href="#four-harness-components-crud-editable" aria-label="Permalink to &quot;Four Harness Components (CRUD-editable)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Component</th><th>Role</th></tr></thead><tbody><tr><td>System prompt (p)</td><td>Instruction and strategic guidance</td></tr><tr><td>Sub-agents (𝒢)</td><td>Specialized modules for specific subtasks</td></tr><tr><td>Skills (𝒦)</td><td>Reusable routines (heuristics + executable code)</td></tr><tr><td>Memory (ℳ)</td><td>Persistent knowledge accumulating across trajectory</td></tr></tbody></table><p><strong>Failure signatures detected</strong>: navigation loops, tool-call errors, stalled objectives.</p><hr><h2 id="experimental-results" tabindex="-1">Experimental Results <a class="header-anchor" href="#experimental-results" aria-label="Permalink to &quot;Experimental Results&quot;">​</a></h2><h3 id="capability-dependent-scaling-pokemon-red-emerald" tabindex="-1">Capability-Dependent Scaling (Pokémon Red + Emerald) <a class="header-anchor" href="#capability-dependent-scaling-pokemon-red-emerald" aria-label="Permalink to &quot;Capability-Dependent Scaling (Pokémon Red + Emerald)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model</th><th>Result</th></tr></thead><tbody><tr><td>Gemini 3 Pro</td><td>Pareto dominance over minimalist baselines; recovers majority of gap to expert harnesses</td></tr><tr><td>Gemini 3 Flash</td><td>High-variance; marginal improvements over baseline</td></tr><tr><td>Gemini 3 Flash-Lite</td><td>All variants underperform baseline — capability floor not met</td></tr></tbody></table><p><strong>Capability floor exists</strong>: Below a minimum capability threshold, refinement cannot bootstrap gains.</p><h3 id="navigation-skill-improvement" tabindex="-1">Navigation Skill Improvement <a class="header-anchor" href="#navigation-skill-improvement" aria-label="Permalink to &quot;Navigation Skill Improvement&quot;">​</a></h3><p>Skills refined during 24-hour runs: navigation cost improved from ~50% penalty vs Dijkstra oracle to single-digit deficits. Improvements persist within episodes via reset-free repair cycles.</p><hr><h2 id="key-findings" tabindex="-1">Key Findings <a class="header-anchor" href="#key-findings" aria-label="Permalink to &quot;Key Findings&quot;">​</a></h2><ol><li><p><strong>Refinement concentrates on small component subsets</strong>: Update operations cluster on bottleneck components (navigation, battle) rather than uniformly across all harness elements → emergent specialization.</p></li><li><p><strong>Harness is the transferable unit</strong>: Inheriting harness from successful runs accelerates subsequent runs. Abandoning inherited sub-agents triggers regressions.</p></li><li><p><strong>Context horizon limits</strong>: Tool generation concentrates in early phases (50-200 steps) of encountering bottlenecks. Beyond 500 turns in stalls, agents cease refining and revert to execution patterns.</p></li><li><p><strong>Reset-free enables within-episode recovery</strong>: Diagnosing and repairing identical failure modes when they recur; accumulating refinement signals from earlier into later trajectory phases.</p></li></ol><hr><h2 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h2><ul><li><strong>Capability floors</strong>: Models below thresholds cannot utilize refined scaffolding</li><li><strong>Convergence unsettled</strong>: Open-source transfer experiments show sustained progress without establishing convergence points</li><li><strong>No reset-free vs reset comparison</strong>: No direct head-to-head against batch accumulation with resets</li></ul><hr><h2 id="workspace-relevance" tabindex="-1">Workspace Relevance <a class="header-anchor" href="#workspace-relevance" aria-label="Permalink to &quot;Workspace Relevance&quot;">​</a></h2><p>Validates the <strong>autoresearch skill&#39;s</strong> Modify→Verify→Keep/Discard loop at the harness level: the Refiner is an autonomous version of the same pattern applied to scaffolding components (system prompt, sub-agents, skills, memory) rather than code.</p>`,38)])])}const u=t(o,[["render",i]]);export{m as __pageData,u as default};
